CREATE OR REPLACE FUNCTION public.audit_asset_changes()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_before_data jsonb;
  v_after_data jsonb;
  v_action_type audit_action_type;
  v_audit_id bigint;
  v_user_name text;
  v_building_number bigint;
BEGIN
  -- Get building number (from OLD for DELETE/UPDATE, from NEW for INSERT)
  v_building_number := COALESCE(OLD.building_number, NEW.building_number);

  -- Determine action type based on operation
  -- Always create ONE audit record with both asset and building data in the same JSON
  IF TG_OP = 'INSERT' THEN
    v_action_type := 'manual_update';
    -- Before: building state (no asset yet) - consistent structure
    v_before_data := jsonb_build_object(
      'asset', NULL,
      'building', (get_building_audit_data(v_building_number)->'building')
    );
    -- After: both asset and building state - consistent structure
    v_after_data := get_asset_audit_data(NEW.asset_id);
  ELSIF TG_OP = 'UPDATE' THEN
    v_action_type := 'manual_update';
    -- Before: both asset and building state before update - consistent structure
    -- Note: Since this is AFTER trigger, building might have been updated by other triggers
    -- but we capture the current state which should reflect pre-update building state
    v_before_data := jsonb_build_object(
      'asset', to_jsonb(OLD.*),
      'building', (get_building_audit_data(v_building_number)->'building')
    );
    -- After: both asset and building state after update - consistent structure
    v_after_data := get_asset_audit_data(NEW.asset_id);
  ELSIF TG_OP = 'DELETE' THEN
    v_action_type := 'manual_update';
    -- Before: both asset and building state before deletion - consistent structure
    v_before_data := get_asset_audit_data(OLD.asset_id);
    -- After: building state (no asset anymore) - consistent structure
    v_after_data := jsonb_build_object(
      'asset', NULL,
      'building', (get_building_audit_data(v_building_number)->'building')
    );
  END IF;

  -- Get current user from session or use default
  BEGIN
    -- Try to get user from Supabase auth context
    v_user_name := coalesce(
      current_setting('request.jwt.claims', true)::json->>'email',
      current_setting('request.jwt.claims', true)::json->>'sub',
      'default'
    );
  EXCEPTION WHEN OTHERS THEN
    v_user_name := 'default';
  END;

  -- Log the audit entry and get the audit_id
  SELECT log_audit_entry(
    v_action_type,
    'asset',
    COALESCE(NEW.asset_id::text, OLD.asset_id::text),
    v_user_name,
    v_before_data,
    v_after_data,
    'Automatic audit log: ' || TG_OP || ' operation on asset'
  ) INTO v_audit_id;

  -- Update the asset's action_id
  IF TG_OP != 'DELETE' THEN
    NEW.action_id := v_audit_id;
  END IF;

  -- Store audit_id in session variable for history trigger to use
  PERFORM set_config('app.current_audit_id', v_audit_id::text, false);

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.audit_building_changes()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_before_data jsonb;
  v_after_data jsonb;
  v_action_type audit_action_type;
  v_audit_id bigint;
  v_user_name text;
BEGIN
  -- Determine action type based on operation
  IF TG_OP = 'INSERT' THEN
    v_action_type := 'manual_update';
    v_before_data := NULL;
    v_after_data := get_building_audit_data(NEW.building_number);
  ELSIF TG_OP = 'UPDATE' THEN
    v_action_type := 'manual_update';
    v_before_data := get_building_audit_data(OLD.building_number);
    v_after_data := get_building_audit_data(NEW.building_number);
  ELSIF TG_OP = 'DELETE' THEN
    v_action_type := 'manual_update';
    v_before_data := get_building_audit_data(OLD.building_number);
    v_after_data := NULL;
  END IF;

  -- Get current user from session or use default
  BEGIN
    -- Try to get user from Supabase auth context
    v_user_name := coalesce(
      current_setting('request.jwt.claims', true)::json->>'email',
      current_setting('request.jwt.claims', true)::json->>'sub',
      'default'
    );
  EXCEPTION WHEN OTHERS THEN
    v_user_name := 'default';
  END;

  -- Log the audit entry and update the building's action_id
  SELECT log_audit_entry(
    v_action_type,
    'building',
    COALESCE(NEW.building_number::text, OLD.building_number::text),
    v_user_name,
    v_before_data,
    v_after_data,
    'Automatic audit log: ' || TG_OP || ' operation on building'
  ) INTO v_audit_id;

  -- Update the building's action_id
  IF TG_OP != 'DELETE' THEN
    NEW.action_id := v_audit_id;
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_asset_audit_data(p_asset_id bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_asset jsonb;
  v_building jsonb;
  v_result jsonb;
BEGIN
  -- Get asset data
  SELECT to_jsonb(a.*) INTO v_asset
  FROM assets a
  WHERE a.asset_id = p_asset_id;

  -- Get building data if asset exists
  IF v_asset IS NOT NULL THEN
    SELECT to_jsonb(b.*) INTO v_building
    FROM buildings b
    WHERE b.building_number = (v_asset->>'building_number')::bigint;
  END IF;

  -- Combine into result
  v_result := jsonb_build_object(
    'asset', v_asset,
    'building', v_building
  );

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_building_audit_data(p_building_number bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_building jsonb;
  v_assets jsonb;
  v_result jsonb;
BEGIN
  -- Get building data
  SELECT to_jsonb(b.*) INTO v_building
  FROM buildings b
  WHERE b.building_number = p_building_number;

  -- Get all assets for this building
  SELECT COALESCE(jsonb_agg(to_jsonb(a.*)), '[]'::jsonb) INTO v_assets
  FROM assets a
  WHERE a.building_number = p_building_number;

  -- Combine into result
  v_result := jsonb_build_object(
    'building', v_building,
    'assets', v_assets
  );

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_or_create_user_from_auth()
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_auth_user_id text;
  v_user_email text;
  v_user_name text;
  v_user_id bigint;
BEGIN
  -- Get current auth user from Supabase auth context
  v_auth_user_id := current_setting('request.jwt.claims', true)::json->>'sub';

  -- If no auth user, return NULL (will use default user)
  IF v_auth_user_id IS NULL THEN
    RETURN NULL;
  END IF;

  -- Try to get user email and name from auth metadata
  v_user_email := current_setting('request.jwt.claims', true)::json->>'email';
  v_user_name := COALESCE(
    current_setting('request.jwt.claims', true)::json->>'email',
    current_setting('request.jwt.claims', true)::json->>'sub',
    'default'
  );

  -- Try to find existing user by auth_user_id
  SELECT user_id INTO v_user_id
  FROM users
  WHERE auth_user_id = v_auth_user_id;

  -- If user exists, return it
  IF v_user_id IS NOT NULL THEN
    RETURN v_user_id;
  END IF;

  -- Create new user
  INSERT INTO users (auth_user_id, user_name, user_email)
  VALUES (v_auth_user_id, v_user_name, v_user_email)
  RETURNING user_id INTO v_user_id;

  RETURN v_user_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.log_audit_for_asset(p_asset_id bigint, p_operation text, p_user_id text DEFAULT NULL::text, p_action_type audit_action_type DEFAULT 'manual_update'::audit_action_type, p_copy_to_history boolean DEFAULT false, p_description text DEFAULT NULL::text)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_before_data jsonb;
  v_after_data jsonb;
  v_audit_id bigint;
  v_old_asset jsonb;
  v_building_number bigint;
BEGIN
  IF p_operation = 'DELETE' THEN
    -- Get old asset before deletion (should have been copied to history already)
    SELECT to_jsonb(ah.*) INTO v_old_asset
    FROM assets_history ah
    WHERE ah.asset_id = p_asset_id
      AND ah.action_id IS NULL
    ORDER BY COALESCE(ah.history_created_at, ah.created_at) DESC NULLS LAST
    LIMIT 1;

    IF v_old_asset IS NOT NULL THEN
      v_building_number := (v_old_asset->>'building_number')::bigint;
      v_before_data := jsonb_build_object(
        'asset', v_old_asset,
        'building', get_building_audit_data(v_building_number)
      );
    END IF;

    v_after_data := jsonb_build_object(
      'asset', NULL,
      'building', get_building_audit_data(v_building_number)
    );
  ELSIF p_operation = 'UPDATE' THEN
    -- For UPDATE, get before data from history if it was copied
    IF p_copy_to_history THEN
      SELECT to_jsonb(ah.*) INTO v_old_asset
      FROM assets_history ah
      WHERE ah.asset_id = p_asset_id
        AND ah.action_id IS NULL
      ORDER BY COALESCE(ah.history_created_at, ah.created_at) DESC NULLS LAST
      LIMIT 1;

      IF v_old_asset IS NOT NULL THEN
        v_building_number := (v_old_asset->>'building_number')::bigint;
        v_before_data := jsonb_build_object(
          'asset', v_old_asset,
          'building', get_building_audit_data(v_building_number)
        );
      END IF;
    ELSE
      -- For regular UPDATE, before_data is not available
      -- Get building number from current asset
      SELECT building_number INTO v_building_number
      FROM assets
      WHERE asset_id = p_asset_id;

      IF v_building_number IS NOT NULL THEN
        v_before_data := jsonb_build_object(
          'asset', NULL,
          'building', get_building_audit_data(v_building_number)
        );
      END IF;
    END IF;

    -- Get after data
    v_after_data := get_asset_audit_data(p_asset_id);
  ELSIF p_operation = 'INSERT' THEN
    -- Get after data
    v_after_data := get_asset_audit_data(p_asset_id);

    -- Get building state for before_data (asset didn't exist before)
    SELECT building_number INTO v_building_number
    FROM assets
    WHERE asset_id = p_asset_id;

    IF v_building_number IS NOT NULL THEN
      v_before_data := jsonb_build_object(
        'asset', NULL,
        'building', get_building_audit_data(v_building_number)
      );
    END IF;
  END IF;

  -- Log audit entry
  SELECT log_audit_entry(
    p_action_type,
    'asset',
    p_asset_id::text,
    p_user_id,
    v_before_data,
    v_after_data,
    p_description
  ) INTO v_audit_id;

  -- Update asset's action_id if not DELETE
  IF p_operation != 'DELETE' THEN
    UPDATE assets
    SET action_id = v_audit_id
    WHERE asset_id = p_asset_id;
  END IF;

  -- Update history entry's action_id if one exists (for DELETE or UPDATE with copy_to_history)
  IF p_operation = 'DELETE' OR (p_operation = 'UPDATE' AND p_copy_to_history) THEN
    -- Update the most recent history entry without action_id
    -- Use a subquery in WHERE clause to identify the row
    UPDATE assets_history
    SET action_id = v_audit_id
    WHERE asset_id = p_asset_id
      AND action_id IS NULL
      AND (building_number, measurement_date, COALESCE(history_created_at, created_at)) = (
        SELECT building_number, measurement_date, COALESCE(history_created_at, created_at)
        FROM assets_history
        WHERE asset_id = p_asset_id
          AND action_id IS NULL
        ORDER BY COALESCE(history_created_at, created_at) DESC NULLS LAST
        LIMIT 1
      );
  END IF;

  RETURN v_audit_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.log_audit_for_building(p_building_number bigint, p_operation text, p_user_id text DEFAULT NULL::text, p_action_type audit_action_type DEFAULT 'manual_update'::audit_action_type, p_description text DEFAULT NULL::text)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_before_data jsonb;
  v_after_data jsonb;
  v_audit_id bigint;
BEGIN
  IF p_operation = 'INSERT' THEN
    v_after_data := get_building_audit_data(p_building_number);
    v_before_data := NULL;
  ELSIF p_operation = 'UPDATE' THEN
    -- Note: This should be called AFTER the update, so v_before_data won't be accurate
    -- The calling code should pass before_data if needed
    v_after_data := get_building_audit_data(p_building_number);
    v_before_data := NULL; -- Will need to be passed in separately if needed
  ELSIF p_operation = 'DELETE' THEN
    v_before_data := NULL; -- Should be passed in before deletion
    v_after_data := NULL;
  END IF;

  SELECT log_audit_entry(
    p_action_type,
    'building',
    p_building_number::text,
    p_user_id,
    v_before_data,
    v_after_data,
    p_description
  ) INTO v_audit_id;

  -- Update building's action_id if not DELETE
  IF p_operation != 'DELETE' THEN
    UPDATE buildings
    SET action_id = v_audit_id
    WHERE building_number = p_building_number;
  END IF;

  RETURN v_audit_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.log_bulk_change_entries(p_entries jsonb)
 RETURNS bigint[]
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_log_ids bigint[];
  v_entry jsonb;
  v_log_id bigint;
  v_user_id_fk bigint;
  v_default_user_id bigint;
BEGIN
  v_log_ids := ARRAY[]::bigint[];

  -- Get default user_id
  SELECT user_id INTO v_default_user_id
  FROM users
  WHERE user_name = 'default' AND auth_user_id IS NULL
  LIMIT 1;

  -- Process each entry in the array
  FOR v_entry IN SELECT * FROM jsonb_array_elements(p_entries)
  LOOP
    -- Get or create user for this entry
    IF v_entry->>'user_id' IS NOT NULL THEN
      SELECT user_id INTO v_user_id_fk
      FROM users
      WHERE auth_user_id = v_entry->>'user_id';

      IF v_user_id_fk IS NULL THEN
        INSERT INTO users (auth_user_id, user_name, user_email)
        VALUES (
          v_entry->>'user_id',
          COALESCE(v_entry->>'user_name', v_entry->>'user_email', 'default'),
          NULLIF(v_entry->>'user_email', '')
        )
        ON CONFLICT (auth_user_id) DO UPDATE
        SET user_name = COALESCE(EXCLUDED.user_name, users.user_name),
            user_email = COALESCE(EXCLUDED.user_email, users.user_email),
            updated_at = now()
        RETURNING user_id INTO v_user_id_fk;
      END IF;
    ELSIF v_entry->>'user_email' IS NOT NULL THEN
      SELECT user_id INTO v_user_id_fk
      FROM users
      WHERE user_email = v_entry->>'user_email'
      LIMIT 1;

      IF v_user_id_fk IS NULL THEN
        INSERT INTO users (user_name, user_email)
        VALUES (
          COALESCE(v_entry->>'user_name', v_entry->>'user_email'),
          v_entry->>'user_email'
        )
        RETURNING user_id INTO v_user_id_fk;
      END IF;
    ELSE
      v_user_id_fk := get_or_create_user_from_auth();
      IF v_user_id_fk IS NULL THEN
        v_user_id_fk := v_default_user_id;
      END IF;
    END IF;

    -- Insert change log entry
    INSERT INTO change_log (
      table_name,
      operation,
      record_id,
      user_id_fk,
      user_name,
      user_email,
      before_data,
      after_data,
      changed_fields
    ) VALUES (
      v_entry->>'table_name',
      v_entry->>'operation',
      v_entry->>'record_id',
      v_user_id_fk,
      COALESCE(v_entry->>'user_name', 'default'),
      NULLIF(v_entry->>'user_email', ''),
      CASE WHEN v_entry->'before_data' IS NOT NULL THEN v_entry->'before_data' ELSE NULL END,
      CASE WHEN v_entry->'after_data' IS NOT NULL THEN v_entry->'after_data' ELSE NULL END,
      CASE WHEN v_entry->'changed_fields' IS NOT NULL THEN ARRAY(SELECT jsonb_array_elements_text(v_entry->'changed_fields')) ELSE NULL END
    )
    RETURNING log_id INTO v_log_id;

    v_log_ids := array_append(v_log_ids, v_log_id);
  END LOOP;

  RETURN v_log_ids;
END;
$function$

CREATE OR REPLACE FUNCTION public.parse_measurement_date(date_str text)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  IF date_str ~ '^\d{2}/\d{2}/\d{4}$' THEN
    RETURN TO_DATE(date_str, 'DD/MM/YYYY');
  ELSE
    RETURN '1900-01-01'::date;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.reset_new_measurement_flag()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'UPDATE' AND COALESCE(NEW.is_new_measurement, false) = true THEN
    -- Set session variable to indicate this is a new measurement
    PERFORM set_config('app.is_new_measurement', 'true', false);
    NEW.is_new_measurement = false;
  ELSE
    -- Clear the session variable
    PERFORM set_config('app.is_new_measurement', 'false', false);
  END IF;
  RETURN NEW;
END;
$function$

